from fractions import Fraction

def verify(answer):
    # expected cups: a 2-lb cake needs 1.5 cups.
    # Two 5-lb cakes total weight = 10 lb, scaling factor = 10/2 = 5
    expected = Fraction(3, 2) * Fraction(10, 2)  # (1.5) * (10/2) = 15/2 = 7.5

    def parse_answer(a):
        s = str(a).strip()
        # try integer first as requested
        try:
            return Fraction(int(s), 1)
        except Exception:
            pass
        # try fraction form like "15/2"
        if '/' in s:
            try:
                return Fraction(s)
            except Exception:
                pass
        # try float form
        try:
            f = float(s)
            return Fraction(f).limit_denominator(1000000)
        except Exception:
            raise ValueError("Cannot parse answer")

    try:
        parsed = parse_answer(answer)
    except Exception:
        return False

    return parsed == expected

