def verify(answer):
    import math
    from sympy import sympify, N
    s = str(answer).strip()
    # try integer
    try:
        x = int(s)
    except Exception:
        # try float
        try:
            x = float(s)
        except Exception:
            # try sympy evaluation (for rationals like "4/1")
            try:
                x = float(N(sympify(s)))
            except Exception:
                return False
    # Must be a real positive number (domain of real log)
    try:
        if not (isinstance(x, (int, float))):
            return False
        if x <= 0 or math.isinf(x) or math.isnan(x):
            return False
    except Exception:
        return False
    # Check the equation log2(x) + log2(x^2) = 6
    try:
        lhs = math.log(x, 2) + math.log(x**2, 2)
    except Exception:
        return False
    return abs(lhs - 6) < 1e-9

