from fractions import Fraction

def verify(answer):
    x = symbols('x')
    f = (6*x**3 + 4*x**2 - 11*x + 5) / (3*x**3 - 15*x + 20)
    try:
        s = str(answer).strip()
    except Exception:
        return False
    # Parse defensively
    cand = None
    try:
        cand = Integer(int(s))
    except Exception:
        try:
            # Try as a rational string like "3/2" or decimal "1.5"
            frac = Fraction(s)
            cand = Rational(frac.numerator, frac.denominator)
        except Exception:
            try:
                cand = sympify(s)
            except Exception:
                return False
    try:
        lim = limit(f, x, float('inf'))
    except Exception:
        # fallback to symbolic infinity
        lim = limit(f, x, sympify('oo'))
    try:
        return (lim - cand).simplify() == 0
    except Exception:
        # final fallback numeric comparison
        try:
            return abs(float(lim) - float(cand)) < 1e-9
        except Exception:
            return False

