def verify(answer):
    import math
    def cbrt(x):
        return math.copysign(abs(x) ** (1.0/3.0), x)
    def f(x):
        return x / (x*x + 1) + 3 * cbrt(x) - 2 * x
    tests = [-10, -3, -2, -1, -0.5, -0.1, 0.0, 0.1, 0.5, 1, 2, 3, 10]
    eps = 1e-8
    is_even = True
    is_odd = True
    for x in tests:
        fx = f(x)
        fmx = f(-x)
        if not (math.isfinite(fx) and math.isfinite(fmx)):
            return False
        if abs(fmx - fx) > eps:
            is_even = False
        if abs(fmx + fx) > eps:
            is_odd = False
    if is_even and not is_odd:
        correct = "even"
    elif is_odd and not is_even:
        correct = "odd"
    else:
        correct = "neither"
    try:
        return str(answer).strip().lower() == correct
    except Exception:
        return False

