def verify(answer):
    # Parse input defensively, allow degree sign or 'deg'
    s = str(answer).strip()
    if s.endswith('°'):
        s = s[:-1].strip()
    if s.lower().endswith('deg'):
        s = s[:-3].strip()
    try:
        A = float(s)
    except Exception:
        # try integer conversion as a fallback
        try:
            A = float(int(str(answer).strip()))
        except Exception:
