    # Compute both sides: cos41 + sin41 and sqrt(2) * sin(A)
    lhs = math.cos(math.radians(41.0)) + math.sin(math.radians(41.0))
    rhs = math.sqrt(2.0) * math.sin(math.radians(A))
    # Allow small numerical tolerance
    return abs(lhs - rhs) <= 1e-9

