def _factorizations(n, start=2):
    # generate non-decreasing factorizations of n into integers >= start
    res = []
    if n == 1:
        return [[]]
    for f in range(start, n + 1):
        if n % f == 0:
            for tail in _factorizations(n // f, f):
                res.append([f] + tail)
    return res

