    except Exception:
        return False

    target = 25
    facts = _factorizations(target, 2)  # factors are the (e_i+1)
    # prepare a list of primes (enough for any factorization length)
    primes = list(primerange(1, 200))
    candidates = []
    for fac in facts:
        # convert factors (e_i+1) to exponents e_i = factor-1
        exponents = [f - 1 for f in fac]
        # to minimize n assign largest exponents to smallest primes
        exponents.sort(reverse=True)
        if len(exponents) > len(primes):
            # not enough primes (shouldn't happen here), skip
            continue
        n = 1
        for p, e in zip(primes, exponents):
            n *= p ** e
        candidates.append(n)
    if not candidates:
        return False
    minimal_n = min(candidates)
    return ans == minimal_n

