    alpha = []
    for n in range(13):
        if n == 0:
            alpha.append(0)
        elif n % 2 == 1:
            alpha.append((n + 1) % MOD)
        else:
            alpha.append((n - 1) % MOD)

    # polynomial represented as list of coefficients [c0, c1, ..., c12]
    def poly_mul(a, b):
        res = [0] * (len(a) + len(b) - 1)
        for i, ai in enumerate(a):
            if ai == 0:
                continue
            for j, bj in enumerate(b):
                res[i + j] = (res[i + j] + ai * bj) % MOD
        return res

    def poly_add(a, b):
        L = max(len(a), len(b))
        res = [0] * L
        for i in range(L):
            ai = a[i] if i < len(a) else 0
            bi = b[i] if i < len(b) else 0
            res[i] = (ai + bi) % MOD
        return res

    # Lagrange interpolation over Z_13 for points (i, alpha[i])
    poly = [0]  # zero polynomial
    xs = list(range(13))
