        for j in xs:
            if j == i:
                continue
            # multiply numer by (x - j) -> coefficients [-j, 1]
            numer = poly_mul(numer, [(-j) % MOD, 1])
            denom = (denom * ((xi - j) % MOD)) % MOD
        # inverse of denom mod MOD
        denom_inv = pow(denom, MOD - 2, MOD)
        scalar = (alpha[i] * denom_inv) % MOD
        term = [(coef * scalar) % MOD for coef in numer]
        poly = poly_add(poly, term)

    # normalize coefficients to length 13
    if len(poly) < 13:
        poly += [0] * (13 - len(poly))
    else:
        poly = poly[:13]

