    d = 0
    for i in range(12, -1, -1):
        if poly[i] % MOD != 0:
            d = i
            break

    a_d = poly[d] % MOD
    a_1 = poly[1] % MOD if len(poly) > 1 else 0
    value = 100 * a_d + a_1

    return ans == value

