    combos = list(combinations(range(n), ones_per_row))
    total = 0

    # backtracking over rows
    rows_left_cache = {}

    def feasible(col_sums, rows_left):
        # For each column, need at most rows_left remaining placements
        for c in col_sums:
            if (ones_per_col - c) > rows_left:
                return False
            if c > ones_per_col:
                return False
        return True

    def dfs(row, col_sums, placed_positions):
        nonlocal total
        if row == n:
            if all(c == ones_per_col for c in col_sums):
                # compute number of groups among placed_positions
                m = len(placed_positions)
                if m == 0:
                    comps = 0
                else:
                    adj = {i: [] for i in range(m)}
                    for i in range(m):
                        r1,c1 = placed_positions[i]
                        for j in range(i+1,m):
                            r2,c2 = placed_positions[j]
                            if r1 == r2 or c1 == c2:
                                adj[i].append(j)
                                adj[j].append(i)
                    seen = [False]*m
                    comps = 0
                    for i in range(m):
                        if not seen[i]:
                            comps += 1
                            dq = [i]
                            seen[i] = True
                            while dq:
                                u = dq.pop()
                                for v in adj[u]:
                                    if not seen[v]:
                                        seen[v] = True
                                        dq.append(v)
                total += (1 << comps)
            return

        rows_left = n - row
        if not feasible(col_sums, rows_left):
            return

        for comb in combos:
            ok = True
            for c in comb:
                if col_sums[c] >= ones_per_col:
                    ok = False
                    break
            if not ok:
                continue
            # choose this combination for current row
            for c in comb:
                col_sums[c] += 1
            for c in comb:
                placed_positions.append((row, c))
            dfs(row+1, col_sums, placed_positions)
            for _ in comb:
                placed_positions.pop()
            for c in comb:
                col_sums[c] -= 1

    dfs(0, col_sums, [])
    return claimed == total

from itertools import combinations

def verify(answer):
    # Generate all strings of length 15 with five 1s, five 2s, five 3s,
    # check adjacency constraint and reducibility by removing 123,231,312 substrings.
    patterns = {"123", "231", "312"}
    memo_global = {}
    def reducible(s):
        # memoize per-string
        if s == "":
            return True
        if s in memo_global:
            return memo_global[s]
        n = len(s)
        for i in range(n - 2):
            if s[i:i+3] in patterns:
                new = s[:i] + s[i+3:]
                if reducible(new):
                    memo_global[s] = True
                    return True
        memo_global[s] = False
        return False

    total = 0
    positions = range(15)
    # choose positions for '1's
    for ones in combinations(positions, 5):
        ones_set = set(ones)
        # choose positions for '2's among remaining
        rem_positions = [p for p in positions if p not in ones_set]
        for twos in combinations(rem_positions, 5):
            twos_set = set(twos)
            # build string as list of chars
            s_list = []
            prev = None
            bad_adj = False
            for i in positions:
                if i in ones_set:
                    ch = '1'
                elif i in twos_set:
                    ch = '2'
                else:
                    ch = '3'
                if prev is not None and prev == ch:
                    bad_adj = True
                    break
                s_list.append(ch)
                prev = ch
            if bad_adj:
                continue
            s = "".join(s_list)
            if reducible(s):
                total += 1

    try:
        return int(str(answer).strip()) == total
    except Exception:
        return False

def verify(answer):
    try:
        s = str(answer).strip()
        n = int(s)
    except Exception:
        try:
            # allow floats that are integer-valued like "24000.0"
            f = float(str(answer).strip())
            if abs(f - round(f)) < 1e-9:
                n = int(round(f))
            else:
                return False
        except Exception:
            return False
    if n <= 0:
        return False
    # From the problem: 100*(600)/N = 2.5  -> 60000/N = 2.5
    # Multiply both sides: 60000 * 2 == 5 * N
    return 60000 * 2 == 5 * n

def verify(answer):
    from math import prod
    from itertools import combinations
    # The champion must drink 16 cups (half of 32), so the other five distinct positive integers sum to 16.
    valid_products = set()
    for comb in combinations(range(1, 16), 5):
        if sum(comb) == 16:
            valid_products.add(prod(comb))
    try:
        ans = int(str(answer).strip())
    except Exception:
        return False
    # If there's a unique valid product, require equality; otherwise accept any valid product.
    if len(valid_products) == 1:
        return ans == next(iter(valid_products))
    return ans in valid_products

from sympy import *
import math

def verify(answer):
    # Build polynomial p(z) = z^8 + i z^6 - (1+i) z^5 + (1-i) z^3 + i z^2 - 1
    z = symbols('z')
    p = z**8 + I*z**6 - (1+I)*z**5 + (1-I)*z**3 + I*z**2 - 1

    # Find numerical roots
    roots = nroots(p)

    # Collect angles theta in [0, pi) for roots with |z| = 1 (within tolerance)
    tol_mod = 1e-6
    tol_ang = 1e-7
    thetas = []
    for r in roots:
        rc = complex(r)  # convert sympy complex to python complex
        if abs(abs(rc) - 1) > tol_mod:
            continue
        ang = math.atan2(rc.imag, rc.real)
        if ang < 0:
            ang += 2*math.pi
        # include angles in [0, pi)
        if ang < math.pi - 1e-9 or abs(ang) < 1e-9:
            # ensure distinct angles
            if not any(abs(ang - t) < tol_ang for t in thetas):
                thetas.append(ang)

    total = sum(thetas)

    # Parse provided answer robustly (allow expressions like pi, 3*pi/2, decimals)
    try:
        # try integer first (per instruction)
        try:
            parsed = int(str(answer).strip())
            ans_val = float(parsed)
        except Exception:
            parsed = sympify(str(answer))
            ans_val = float(N(parsed))
    except Exception:
        try:
            ans_val = float(str(answer))
        except Exception:
            return False

    return abs(ans_val - total) < 1e-6

from sympy import sympify, N
import math

def verify(answer):
    # compute perimeter = integral_0^{2pi} |f'(theta)| dtheta
    # where f'(theta) = i(e^{iθ} + 2 e^{2iθ} + e^{3iθ}), so magnitude = |e^{iθ} + 2 e^{2iθ} + e^{3iθ}|
    def integrand(theta):
        # compute complex exponentials via cos/sin
        a = complex(math.cos(theta), math.sin(theta))            # e^{iθ}
        b = complex(math.cos(2*theta), math.sin(2*theta))        # e^{2iθ}
        c = complex(math.cos(3*theta), math.sin(3*theta))        # e^{3iθ}
        s = a + 2*b + c
        return abs(s)
    # composite Simpson's rule (N must be even)
    Npts = 20000
    if Npts % 2 == 1:
        Npts += 1
    a0 = 0.0
    b0 = 2*math.pi
    h = (b0 - a0) / Npts
    s = integrand(a0) + integrand(b0)
    for k in range(1, Npts):
        coeff = 4 if (k % 2 == 1) else 2
        s += coeff * integrand(a0 + k*h)
    perimeter = s * (h/3.0)
    # parse answer defensively
    val = None
    ans_str = str(answer).strip()
    try:
        val = int(ans_str)
    except Exception:
        try:
            val = float(ans_str)
        except Exception:
            try:
                val = float(N(sympify(ans_str)))
            except Exception:
                return False
    # compare with tolerance
    tol = 1e-5
    return abs(val - perimeter) <= tol * max(1.0, abs(perimeter))

def verify(answer):
    try:
        claimed = int(str(answer).strip())
    except Exception:
        return False

    patterns = {"123", "231", "312"}
    memo = {}

    def reducible(s):
        if s == "":
            return True
        if s in memo:
            return memo[s]
        n = len(s)
        for i in range(n - 2):
            if s[i:i+3] in patterns:
                if reducible(s[:i] + s[i+3:]):
                    memo[s] = True
                    return True
        memo[s] = False
        return False

    chars = "123"
    counts = [5, 5, 5]
    total = 0

    # backtrack over all length-15 strings with exactly five of each char and no equal adjacent chars
    def build(prev_idx, counts, cur):
        nonlocal total
        if counts[0] + counts[1] + counts[2] == 0:
            if reducible(cur):
                total += 1
            return
        for i in range(3):
            if counts[i] > 0 and i != prev_idx:
                counts[i] -= 1
                build(i, counts, cur + chars[i])
                counts[i] += 1

    build(-1, counts, "")
    return claimed == total
